def get_all_states():
    return sorted(LOCATION_DATA.keys())

def get_districts(state):
    d = sorted(LOCATION_DATA.get(state, {}).keys())
    return d if d else ["District data not available"]

def get_tehsils(state, district):
    t = LOCATION_DATA.get(state, {}).get(district, [])
